// src/components/Calendar.js
import React, { useState } from 'react';
import FullCalendar from '@fullcalendar/react'; // Importa o componente do FullCalendar
import dayGridPlugin from '@fullcalendar/daygrid'; // Importa o plugin para o layout de grade (grid)

const Calendar = () => {
  // Definindo o estado dos eventos do calendário usando o hook useState
  const [events, setEvents] = useState([
    { title: 'Evento 1', date: '2024-10-03' },
    { title: 'Evento 2', date: '2024-10-12' }
  ]);

  return (
    <div>
      <FullCalendar
        plugins={[dayGridPlugin]} // Usando o plugin de grade
        initialView="dayGridMonth" // Exibe o mês como visualização inicial
        events={events} // Passando os eventos para o calendário
      />
    </div>
  );
};

export default Calendar;
